CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE TYPE "Role" AS ENUM ('USER','PREMIUM','MODERATOR','ADMIN');
CREATE TYPE "Visibility" AS ENUM ('PUBLIC','PRIVATE');
CREATE TYPE "PostType" AS ENUM ('TEXT','IMAGE','LINK');
CREATE TYPE "NotificationType" AS ENUM ('LIKE','COMMENT','FOLLOW','MESSAGE','SYSTEM','REPORT');
CREATE TYPE "ReportStatus" AS ENUM ('OPEN','REVIEWING','RESOLVED','REJECTED');
CREATE TYPE "MarketplaceStatus" AS ENUM ('ACTIVE','SOLD','ARCHIVED');
CREATE TYPE "JobType" AS ENUM ('FULL_TIME','PART_TIME','CONTRACT','REMOTE');

CREATE TABLE "User" ("id" TEXT PRIMARY KEY DEFAULT uuid_generate_v4(),"email" TEXT NOT NULL UNIQUE,"username" TEXT NOT NULL UNIQUE,"passwordHash" TEXT NOT NULL,"role" "Role" NOT NULL DEFAULT 'USER',"emailVerifiedAt" TIMESTAMP(3),"twoFactorSecret" TEXT,"twoFactorEnabled" BOOLEAN NOT NULL DEFAULT false,"status" TEXT NOT NULL DEFAULT 'online',"reputation" INTEGER NOT NULL DEFAULT 0,"premiumUntil" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Profile" ("id" TEXT PRIMARY KEY DEFAULT uuid_generate_v4(),"userId" TEXT NOT NULL UNIQUE REFERENCES "User"("id") ON DELETE CASCADE,"avatarUrl" TEXT,"coverUrl" TEXT,"bio" TEXT,"city" TEXT,"socialLinks" JSONB NOT NULL DEFAULT '{}',"stats" JSONB NOT NULL DEFAULT '{}');
CREATE TABLE "RefreshToken" ("id" TEXT PRIMARY KEY DEFAULT uuid_generate_v4(),"userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"tokenHash" TEXT NOT NULL UNIQUE,"userAgent" TEXT,"ip" TEXT,"expiresAt" TIMESTAMP(3) NOT NULL,"revokedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Community" ("id" TEXT PRIMARY KEY DEFAULT uuid_generate_v4(),"ownerId" TEXT NOT NULL,"name" TEXT NOT NULL,"slug" TEXT NOT NULL UNIQUE,"description" TEXT,"visibility" "Visibility" NOT NULL DEFAULT 'PUBLIC',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Post" ("id" TEXT PRIMARY KEY DEFAULT uuid_generate_v4(),"authorId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"content" TEXT NOT NULL,"type" "PostType" NOT NULL DEFAULT 'TEXT',"mediaUrls" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[],"communityId" TEXT REFERENCES "Community"("id"),"repostOfId" TEXT REFERENCES "Post"("id"),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX "Post_createdAt_idx" ON "Post"("createdAt"); CREATE INDEX "Post_authorId_idx" ON "Post"("authorId");
CREATE TABLE "Comment" ("id" TEXT PRIMARY KEY DEFAULT uuid_generate_v4(),"postId" TEXT NOT NULL REFERENCES "Post"("id") ON DELETE CASCADE,"authorId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"parentId" TEXT REFERENCES "Comment"("id"),"content" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Like" ("id" TEXT PRIMARY KEY DEFAULT uuid_generate_v4(),"userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"postId" TEXT NOT NULL REFERENCES "Post"("id") ON DELETE CASCADE,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,UNIQUE("userId","postId"));
CREATE TABLE "SavedPost" ("userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"postId" TEXT NOT NULL REFERENCES "Post"("id") ON DELETE CASCADE,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY("userId","postId"));
CREATE TABLE "ForumCategory" ("id" TEXT PRIMARY KEY DEFAULT uuid_generate_v4(),"slug" TEXT NOT NULL UNIQUE,"title" TEXT NOT NULL,"description" TEXT);
CREATE TABLE "ForumTopic" ("id" TEXT PRIMARY KEY DEFAULT uuid_generate_v4(),"categoryId" TEXT NOT NULL REFERENCES "ForumCategory"("id"),"authorId" TEXT NOT NULL,"title" TEXT NOT NULL,"content" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "CommunityMember" ("userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"communityId" TEXT NOT NULL REFERENCES "Community"("id") ON DELETE CASCADE,"role" "Role" NOT NULL DEFAULT 'USER',"joinedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY("userId","communityId"));
CREATE TABLE "Chat" ("id" TEXT PRIMARY KEY DEFAULT uuid_generate_v4(),"title" TEXT,"isGroup" BOOLEAN NOT NULL DEFAULT false,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "ChatMember" ("chatId" TEXT NOT NULL REFERENCES "Chat"("id") ON DELETE CASCADE,"userId" TEXT NOT NULL,"joinedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY("chatId","userId"));
CREATE TABLE "Message" ("id" TEXT PRIMARY KEY DEFAULT uuid_generate_v4(),"chatId" TEXT NOT NULL REFERENCES "Chat"("id") ON DELETE CASCADE,"authorId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"content" TEXT NOT NULL,"attachments" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[],"reactions" JSONB NOT NULL DEFAULT '{}',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "JobPost" ("id" TEXT PRIMARY KEY DEFAULT uuid_generate_v4(),"company" TEXT NOT NULL,"title" TEXT NOT NULL,"description" TEXT NOT NULL,"city" TEXT,"type" "JobType" NOT NULL DEFAULT 'REMOTE',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "JobApplication" ("id" TEXT PRIMARY KEY DEFAULT uuid_generate_v4(),"jobId" TEXT NOT NULL REFERENCES "JobPost"("id") ON DELETE CASCADE,"userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"resumeUrl" TEXT,"coverText" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "MarketplaceItem" ("id" TEXT PRIMARY KEY DEFAULT uuid_generate_v4(),"sellerId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"title" TEXT NOT NULL,"description" TEXT NOT NULL,"price" DECIMAL(12,2) NOT NULL,"category" TEXT NOT NULL,"photoUrls" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[],"status" "MarketplaceStatus" NOT NULL DEFAULT 'ACTIVE',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Report" ("id" TEXT PRIMARY KEY DEFAULT uuid_generate_v4(),"authorId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"postId" TEXT REFERENCES "Post"("id"),"commentId" TEXT REFERENCES "Comment"("id"),"reason" TEXT NOT NULL,"status" "ReportStatus" NOT NULL DEFAULT 'OPEN',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Notification" ("id" TEXT PRIMARY KEY DEFAULT uuid_generate_v4(),"userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"type" "NotificationType" NOT NULL,"title" TEXT NOT NULL,"body" TEXT NOT NULL,"readAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Achievement" ("id" TEXT PRIMARY KEY DEFAULT uuid_generate_v4(),"code" TEXT NOT NULL UNIQUE,"title" TEXT NOT NULL,"description" TEXT NOT NULL);
CREATE TABLE "UserAchievement" ("userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"achievementId" TEXT NOT NULL REFERENCES "Achievement"("id") ON DELETE CASCADE,"awardedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY("userId","achievementId"));
CREATE TABLE "Subscription" ("id" TEXT PRIMARY KEY DEFAULT uuid_generate_v4(),"userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"plan" TEXT NOT NULL,"status" TEXT NOT NULL,"startsAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"endsAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "AuditLog" ("id" TEXT PRIMARY KEY DEFAULT uuid_generate_v4(),"actorId" TEXT REFERENCES "User"("id"),"action" TEXT NOT NULL,"entity" TEXT NOT NULL,"entityId" TEXT,"metadata" JSONB NOT NULL DEFAULT '{}',"ip" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
